#include <bits/stdc++.h>
using namespace std;
int t,n,a[100005],mx,mn;
int main()
{
	cin>>t;
	while(t--)
	{
		cin>>n;
		mx=0;
		mn=1e9;
		for(int i=1;i<=n;i++) cin>>a[i];
		for(int i=1;i<=n;i++)
		{
			int x;
			cin>>x;
			mx=max(mx,a[i]+x);
			mn=min(mn,a[i]-x);
		}
		cout<<(double)((double)mx+(double)mn)/2.0<<'\n';
	}
	return 0;
}
